Here's a production-quality thread-safe LRU cache:

```go
package lru

import (
    "container/list"
    "sync"
)

type entry struct {
    key   string
    value interface{}
}

type Cache struct {
    mu       sync.Mutex
    capacity int
    items    map[string]*list.Element
    order    *list.List
}

func New(capacity int) *Cache {
    return &Cache{
        capacity: capacity,
        items:    make(map[string]*list.Element, capacity),
        order:    list.New(),
    }
}

func (c *Cache) Get(key string) (interface{}, bool) {
    c.mu.Lock()
    defer c.mu.Unlock()
    elem, ok := c.items[key]
    if !ok {
        return nil, false
    }
    c.order.MoveToFront(elem)
    return elem.Value.(*entry).value, true
}

func (c *Cache) Put(key string, value interface{}) {
    c.mu.Lock()
    defer c.mu.Unlock()
    if elem, ok := c.items[key]; ok {
        elem.Value.(*entry).value = value
        c.order.MoveToFront(elem)
        return
    }
    if c.order.Len() >= c.capacity {
        oldest := c.order.Back()
        if oldest != nil {
            c.order.Remove(oldest)
            delete(c.items, oldest.Value.(*entry).key)
        }
    }
    e := &entry{key: key, value: value}
    elem := c.order.PushFront(e)
    c.items[key] = elem
}

func (c *Cache) Len() int {
    c.mu.Lock()
    defer c.mu.Unlock()
    return c.order.Len()
}
```

Here's a generic version with TTL and eviction callback:

```go
package lru

import (
    "container/list"
    "sync"
    "time"
)

type entry[K comparable, V any] struct {
    key       K
    value     V
    expiresAt time.Time
}

type Options[K comparable, V any] struct {
    Capacity  int
    TTL       time.Duration // 0 means no expiry
    OnEvict   func(K, V)    // called when an entry is evicted
}

type Cache[K comparable, V any] struct {
    mu       sync.Mutex
    opts     Options[K, V]
    items    map[K]*list.Element
    order    *list.List
    stopCh   chan struct{}
}

func New[K comparable, V any](opts Options[K, V]) *Cache[K, V] {
    c := &Cache[K, V]{
        opts:   opts,
        items:  make(map[K]*list.Element, opts.Capacity),
        order:  list.New(),
        stopCh: make(chan struct{}),
    }
    if opts.TTL > 0 {
        go c.startCleanup()
    }
    return c
}

func (c *Cache[K, V]) Get(key K) (V, bool) {
    c.mu.Lock()
    defer c.mu.Unlock()
    elem, ok := c.items[key]
    if !ok {
        var zero V
        return zero, false
    }
    e := elem.Value.(*entry[K, V])
    if !e.expiresAt.IsZero() && time.Now().After(e.expiresAt) {
        c.removeElement(elem)
        var zero V
        return zero, false
    }
    c.order.MoveToFront(elem)
    return e.value, true
}

func (c *Cache[K, V]) Put(key K, value V) {
    c.mu.Lock()
    defer c.mu.Unlock()
    if elem, ok := c.items[key]; ok {
        e := elem.Value.(*entry[K, V])
        e.value = value
        if c.opts.TTL > 0 {
            e.expiresAt = time.Now().Add(c.opts.TTL)
        }
        c.order.MoveToFront(elem)
        return
    }
    if c.order.Len() >= c.opts.Capacity {
        c.evictOldest()
    }
    e := &entry[K, V]{key: key, value: value}
    if c.opts.TTL > 0 {
        e.expiresAt = time.Now().Add(c.opts.TTL)
    }
    elem := c.order.PushFront(e)
    c.items[key] = elem
}

func (c *Cache[K, V]) evictOldest() {
    oldest := c.order.Back()
    if oldest != nil {
        c.removeElement(oldest)
    }
}

func (c *Cache[K, V]) removeElement(elem *list.Element) {
    e := elem.Value.(*entry[K, V])
    c.order.Remove(elem)
    delete(c.items, e.key)
    if c.opts.OnEvict != nil {
        c.opts.OnEvict(e.key, e.value)
    }
}

func (c *Cache[K, V]) startCleanup() {
    ticker := time.NewTicker(c.opts.TTL / 2)
    defer ticker.Stop()
    for {
        select {
        case <-ticker.C:
            c.cleanupExpired()
        case <-c.stopCh:
            return
        }
    }
}

func (c *Cache[K, V]) cleanupExpired() {
    c.mu.Lock()
    defer c.mu.Unlock()
    now := time.Now()
    for e := c.order.Back(); e != nil; {
        prev := e.Prev()
        entry := e.Value.(*entry[K, V])
        if !entry.expiresAt.IsZero() && now.After(entry.expiresAt) {
            c.removeElement(e)
        }
        e = prev
    }
}

func (c *Cache[K, V]) Close() {
    close(c.stopCh)
}
```

Adding metrics is straightforward since we already track every operation. Add these to the struct and methods:

```go
type Stats struct {
    Hits      int64
    Misses    int64
    Evictions int64
    Size      int
    Capacity  int
}

type Cache[K comparable, V any] struct {
    // ... existing fields ...
    stats Stats
}

// In Get, after finding a valid entry:
//     atomic.AddInt64(&c.stats.Hits, 1)
// In Get, after a miss or expiry:
//     atomic.AddInt64(&c.stats.Misses, 1)
// In removeElement, after OnEvict:
//     atomic.AddInt64(&c.stats.Evictions, 1)

func (c *Cache[K, V]) Stats() Stats {
    c.mu.Lock()
    defer c.mu.Unlock()
    return Stats{
        Hits:      atomic.LoadInt64(&c.stats.Hits),
        Misses:    atomic.LoadInt64(&c.stats.Misses),
        Evictions: atomic.LoadInt64(&c.stats.Evictions),
        Size:      c.order.Len(),
        Capacity:  c.opts.Capacity,
    }
}
```

Using `atomic.Int64` for the counters avoids contention on the main mutex for stats reads. The `Size` and `Capacity` fields are read under the mutex since they're not performance-critical and need consistency with the current state.
